fn solve(weight: Vec<i64>) -> i64 {
    let mut max_count = 0;
    let mut start = 0;
    let mut max_so_far = 0;

    for end in 0..weight.len() {
        max_so_far = std::cmp::max(max_so_far, weight[end]);

        if weight[end] < max_so_far {
            max_count += 1;
            start = end + 1;
            max_so_far = 0;
        }
    }

    max_count
}
