function solve(weight: number[]): number {
    let maxCount = 0;
    let start = 0;
    let maxSoFar = 0;

    for (let end = 0; end < weight.length; end++) {
        maxSoFar = Math.max(maxSoFar, weight[end]);

        // Check if the current subarray is a balanced shipment
        if (weight[end] < maxSoFar) {
            maxCount++;
            start = end + 1;
            maxSoFar = 0;
        }
    }

    return maxCount;
}
